module dram_cell (
    input wire clk,
    input wire write_enable,
    input wire data_in,
    output reg data_out
);
    reg dram_stored_data;

    always @(posedge clk) begin
        if (write_enable) begin
            dram_stored_data <= data_in;
        end
    end

    always @(posedge clk) begin
        data_out <= dram_stored_data;
    end
endmodule
